import React from "react";
import { CardInterface } from "../method/methodCard";
import { TextEditor } from "./textEditor";
import { useLocation } from "react-router-dom";
import { pagesData } from '../pagesData/pages'

export const Page:React.FC = () => {
	const location = useLocation();
	const pageName: string | null = new URLSearchParams(location.search).get('name');
	const card = pagesData.find((card: { link: string | null; }) => card.link === pageName)
	return (
		<section>
			<section>
      <img
        style={{ maxHeight: 350, display: 'block', margin: '0 auto' }}
        src={card!.image}
        alt={card!.title}
      />
      <TextEditor  style={{ marginInline: 'auto' }} content={card!.text} />
    </section>
		</section>
	)
}
